def cmd_stats(args):
    loadTasks()
    total = len(TASKS)
    by_status = {}
    by_priority = {}
    overdue = 0
    for t in TASKS:
        st = t.get("status", "todo")
        by_status[st] = by_status.get(st, 0) + 1
        pr = t.get("priority", "normal")
        by_priority[pr] = by_priority.get(pr, 0) + 1
        if is_overdue(t):
            overdue += 1
    print("total tasks: %d" % total)
    print("by status:")
    for st in STATUSES:
